import '../models/models.dart';

List<Course> buildCourses() {
  return [
    Course(
      id: 'fievre',
      name: 'Fièvre',
      cards: [
        Flashcard(id: 'fievre_1', question: 'Définition de la fièvre ?', answer: 'Fébricule = T° entre 37,5° et 38° / Fièvre = T° > 38° le matin et > 38,3° le soir / Fièvre élevée = 39° / Hyperthermie = > 41°'),
        Flashcard(id: 'fievre_2', question: 'Principales causes de fièvre ?', answer: 'Maladies infectieuses+++ (virales bénignes prédominantes), maladies inflammatoires, MAI, maladies de système, néoplasies/hémopathies malignes, MTE'),
        Flashcard(id: 'fievre_3', question: 'Physiopathologie de la fièvre ?', answer: 'Pyrogènes (exogènes : toxines bactériennes / endogènes : cytokines inflammatoires) → stimulation synthèse PGE2 → dérèglement thermostat hypothalamique'),
        Flashcard(id: 'fievre_4', question: 'Fièvre continue ou en plateau : définition et causes ?', answer: 'T° à 40° avec faible rémission de 0,5° le matin. Causes : FT 2e semaine, septicémies, palu primo-invasion'),
        Flashcard(id: 'fievre_5', question: 'Fièvre rémittente : définition et causes ?', answer: 'T° subnormale le matin avec élévation progressive max le soir. Causes : TBC, suppurations profondes'),
        Flashcard(id: 'fievre_6', question: 'Fièvre intermittente : définition et causes ?', answer: 'Accès de fièvre séparés par intervalles d\'apyrexie totale régulièrement (accès palustre) ou irrégulièrement espacés (cholécystite)'),
        Flashcard(id: 'fievre_7', question: 'Fièvre ondulante : définition et causes ?', answer: 'Poussées de fièvre à début et fin progressifs alternant avec rémissions thermiques complètes sur semaines/mois. Causes : Hodgkin, brucellose, endocardite'),
        Flashcard(id: 'fievre_8', question: 'Classification de la fièvre selon la durée ?', answer: 'Aiguë récente < 5 jrs / Persistante entre 5 et 20 jrs / Prolongée ou au long cours > 20 jrs'),
        Flashcard(id: 'fievre_9', question: 'Quand utiliser les antipyrétiques ?', answer: 'Hyperthermie mettant en jeu le pronostic vital, extrêmes d\'âge (NRS : risque CVS / vieillard : risque DSH, troubles comportement), infection bénigne. Sinon le trt étiologique suffit'),
      ],
    ),
    Course(
      id: 'sd_meningee',
      name: 'Syndrome Méningé',
      cards: [
        Flashcard(id: 'sd_meningee_1', question: 'Définition du syndrome méningé ?', answer: 'Ensemble des manifestations cliniques en rapport avec l\'irritation des enveloppes méningées. Urgence diagnostique et thérapeutique. 2 étiologies : méningite infectieuse et HM'),
        Flashcard(id: 'sd_meningee_2', question: 'Syndrome méningé fonctionnel ?', answer: 'Céphalées (+++) : intense, en casque, rebelle aux antalgiques, paroxystiques avec photophobie et phonophobie / VMS : faciles en jet, répétés, rythmés par les céphalées / Constipation inconstante'),
        Flashcard(id: 'sd_meningee_3', question: 'Syndrome méningé physique ?', answer: 'Raideur de la nuque (+++) : signe cst et précoce, antéflexion limitée / Signe de Brudzinski / Signe de Kernig / Position en chien de fusil / Hyperesthésie cutanée'),
        Flashcard(id: 'sd_meningee_4', question: 'Signes encéphalitiques : signification et exemples ?', answer: 'Témoignent de la gravité → TDM cérébrale obligatoire. Exemples : signes de focalisation, CVS, troubles psychiques, troubles de conscience, troubles neuro-végétatifs'),
        Flashcard(id: 'sd_meningee_5', question: 'Ponction lombaire : point de ponction et technique ?', answer: 'Entre L4-L5 ou L3-L4 ou L5-S1 (intersection ligne horizontale crêtes iliaques et ligne verticale des épineuses). DL ou assis le dos rond. Piquer de manière ascendante. 3 tubes : bioch/cyto/bactério'),
        Flashcard(id: 'sd_meningee_6', question: 'Contre-indications à la PL ?', answer: 'Neurologiques : suspicion processus intracrânien, signes d\'HIC/engagement, CVS persistantes / Non neurologiques : infection cutanée du site, instabilité hémodynamique/respi, troubles hémostase (plaquettes < 25-50.000)'),
        Flashcard(id: 'sd_meningee_7', question: 'LCS normal : caractéristiques ?', answer: 'Clair "eau de roche" et stérile, albumine < 0,5 g/l, glucose ≥ ½ glycémie, chlore 110-130 mEq/ml, lactate < 3 µmol/ml, < 10 éléments/mm3 (lymphocytes, absence de PN)'),
        Flashcard(id: 'sd_meningee_8', question: 'Qu\'est-ce que le méningisme ?', answer: 'Syndrome méningé + LCS normal. Causes : PFLA, palu, otite, FT'),
      ],
    ),
    Course(
      id: 'meningite_pneumo',
      name: 'Méningite à Pneumocoque',
      cards: [
        Flashcard(id: 'mpneumo_1', question: 'Microbiologie du pneumocoque ?', answer: 'Streptococcus pneumoniae, CGP (diplocoque, forme lancéolée en "flamme de bougie", encapsulé, aéro-anaérobie facultatif), hémolyse α (partielle), culture sur gélose de sang, sensible à l\'optochine'),
        Flashcard(id: 'mpneumo_2', question: 'Epidémiologie et transmission de la méningite à pneumocoque ?', answer: '2e après la MCS, grave et mortelle sans trt. Infections fréquentes et essentiellement communautaires. Réservoir : VAS des sujets sains et malades. Transmission : interhumaine directe aérienne'),
        Flashcard(id: 'mpneumo_3', question: 'Facteurs favorisants la méningite à pneumocoque ?', answer: 'Saison hivernale, infection de voisinage (trauma base crâne, mastoïdite, sinusite)+++ , altération clairance ciliaire (BPCO, asthme, tabagisme), ID (VIH, diabète, splénectomie+++, myélome), maladies chroniques'),
        Flashcard(id: 'mpneumo_4', question: 'Clinique de la méningite à pneumocoque ?', answer: 'Début brutal explosif (avec ATCD d\'infection ORL ou pneumonie). SG : fièvre élevée 39-40°C, frissons, AEG. SF : syndrome méningé fonctionnel et signes encéphalitiques+++ (CVS, obnubilation, agitation). SP : syndrome méningé physique, herpès naso-labial'),
        Flashcard(id: 'mpneumo_5', question: 'Complications infectieuses de la méningite à pneumocoque ?', answer: 'Abcès cérébral, empyème, ventriculite'),
        Flashcard(id: 'mpneumo_6', question: 'Complications mécaniques (NRS+++) ?', answer: 'HTIC, hypotension intracrânienne, cloisonnement méningé, hématome sous-dural'),
        Flashcard(id: 'mpneumo_7', question: 'Séquelles de la méningite à pneumocoque ?', answer: 'Moyen terme : hydrocéphalie ou déficit moteur / Long terme : surdité+++, cécité, mutité, comitialité, troubles psychomoteurs, paralysie des nerfs crâniens (oculomoteurs et facial)'),
        Flashcard(id: 'mpneumo_8', question: 'Examens de certitude de la méningite à pneumocoque ?', answer: 'PL : liquide hypertendu, trouble ou purulent (peut être clair si débutante), cyto >1000 PNA/mm3, albumine >2-3 g/l, glucose diminuée <½ glycémie, examen direct (diplocoque GP). Recherche Ag solubles si ATB préalable'),
        Flashcard(id: 'mpneumo_9', question: 'Traitement curatif sans signes de gravité ?', answer: 'C3G (céfotaxime ou ceftriaxone) + CTC en IV pdt 15-21 jrs. Trt adjuvant : dexaméthasone IV pdt 4 jrs (doit débuter en même temps que l\'ATB)'),
        Flashcard(id: 'mpneumo_10', question: 'Traitement curatif avec signes de gravité ou facteurs prédisposants à PSDP ?', answer: 'C3G + glycopeptide (vancomycine) + CTC. Si allergie β-lactamines : remplacer C3G par phénicolés. Si CI vancomycine : remplacer par rifampicine'),
        Flashcard(id: 'mpneumo_11', question: 'Facteurs prédisposants à un PSDP ?', answer: 'Âges extrêmes, prise de β-lactamines dans les 3-6 mois, ATCD de pneumopathies, terrain favorisant (VIH)'),
        Flashcard(id: 'mpneumo_12', question: 'Prévention de la méningite à pneumocoque ?', answer: 'Déclaration de la maladie. Vaccination chez sujets prédisposés : Prevenar13 puis 2 mois après Pneumo23, avec rappel tous les 5 ans'),
      ],
    ),
    Course(
      id: 'pneumonie_pneumo',
